// 性能配置接口
export interface PerformanceSettings {
  // Skeleton动画开关
  enableSkeletonAnimation: boolean;

  // 刮卡效果频率（0-1，1为全频率，0.5为减半）
  scratchEffectFrequency: number;

  // 纹理更新间隔（毫秒，0表示立即更新）
  scratchTextureUpdateInterval: number;

  // 落叶效果开关
  enableLeafParticles: boolean;

  // 叶子生成数量百分比（0-1，表示每个格子最多生成的叶子数量占格子面积的百分比）
  maxLeafPerCellPercent: number;

  // 物理引擎开关（如果关闭，叶子使用tween动画掉落）
  enablePhysics2D: boolean;

  // 设备性能等级
  level: string;
}

