    if (gameId) {
      this.gameId = gameId;
    }

    this._urlParams = {
      token,
      gameId,
      lang,
      callbackUrl,
      playType,
      productId,
    };

    // 如果playType不为空，则设置当前游戏玩法
    if (playType) {
      this.currentPlayType = playType;
    }
    if (gameId) {
      this.gameId = gameId;
    }
    if (token) {
      this.token = token;
    }
