  getCurrentCardPrice(playType: string) {
    let price = 0;
    if (!this || !this.gameList) {
      return price;
    }
    let curPrice = this.gameList.find(
      (game) => game.playType === playType,
    )?.unitPrice;

    switch (playType) {
      case "GO_BANANAS":
        price = 20;
        break;
      case "SEVEN_SEVEN_SEVEN":
        price = 20;
        break;
      case "INSTANT_KENO":
        price = 50;
        break;
      case "LUCKY_COLORS":
        price = 20;
        break;
      case "IN_BETWEEN":
        price = 20;
        break;
      case "BINGO_CARD":
        price = 50;
        break;
      case "GINTO_SCRATCH":
        price = 20;
        break;
      case "PIKA_SCRATCH":
        price = 20;
        break;
      case "LUCKY_NUMBER_SCRATCH":
        price = 20;
        break;
      case "HALO_SCRATCH":
        price = 20;
        break;
      default:
        price = 20;
        break;
    }
    return curPrice || price;
  }
